-- Enrichment marathon batch: Mouseflow, Movim, Mox, Moz Pro, mpd (Music Player Daemon), mStream, MTA:SA, multi-scrobbler

-- ── Mouseflow ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mouseflow is a website behavior analytics platform that combines session replay, heatmaps, funnels, and form analytics to help teams find and fix friction in the user experience.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $25/month)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Around 60 employees$q$, company_size),
  headquarters = COALESCE($q$Copenhagen, Denmark$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mouseflow Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mouseflow review 2026: see how this Copenhagen-built heatmap and session replay tool prices, what it tracks, and how it compares to Hotjar and Crazy Egg.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mouseflow is a behavior analytics and conversion rate optimization platform founded in Denmark by Lasse Schou Holboll (Crunchbase lists the founding year as 2009, though some Mouseflow materials reference 2010). The company is headquartered in Copenhagen, Denmark, and by 2025 reported serving more than 190,000 digital experience professionals across marketing, product, UX, analytics, and CRO teams worldwide, with roughly 60 employees spread across Europe, North America, and Asia. Mouseflow was reported as acquired in August 2025. The product works by embedding a lightweight JavaScript tracking snippet on a website, which then records anonymized visitor sessions and aggregates interaction data into heatmaps and analytics dashboards, requiring no code changes to implement. Core capabilities include session replay (video-like playback of real visitor sessions), five heatmap types (click, scroll, movement, attention, and geographical), conversion funnel analysis, user journey mapping, form analytics that show field-level abandonment and completion rates, a proprietary Friction Score that automatically flags sessions where users struggled (rage clicks, dead clicks, error clicks, or excessive scrolling), and on-page feedback surveys. Higher tiers add an open REST API, MCP (Model Context Protocol) connectivity for AI workflows, single sign-on, and dedicated customer success support. Pricing follows a freemium model: a permanent Free plan covers 500 sessions per month on one website with one conversion funnel and one month of data retention; paid plans start with Essential at 25 per month (5,000 sessions, one project, three months retention), scaling through Advanced at 109 per month (25,000 sessions, form and journey analytics, feedback surveys) and Premium at 319 per month (100,000 sessions, API access, MCP, SSO), up to a custom-priced Enterprise tier with unlimited sessions and a dedicated SLA. Annual billing is discounted versus monthly. Mouseflow's target audience spans small business marketers, ecommerce teams, product/UX researchers, and CRO agencies who need to understand why visitors abandon carts, forms, or signup flows rather than just what pages they viewed. Its primary competitors are Hotjar, Crazy Egg, FullStory, Contentsquare, and Microsoft Clarity (a free alternative). Mouseflow differentiates on its combination of comprehensive heatmap types plus session replay plus the Friction Score in a single unified platform, its GDPR-oriented data handling for the EU market given its Danish base, and depth of form-analytics tooling relative to lower-cost competitors like Clarity.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e44be36-57f9-4e4f-b5f8-22e6508f69b4';

