-- ── Movim ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Movim is a free, open-source, decentralized social network and web-based XMPP client that lets people chat, publish posts, and join communities across federated servers.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Movim Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Movim review 2026: how this open-source, decentralized XMPP social network and webmail platform works, its features, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Movim, short for My Open Virtual Identity Manager, is a free and open-source decentralized social network and webmail platform built entirely on top of the XMPP (Extensible Messaging and Presence Protocol) open standard. The project was founded by developer Timothee Jaussoin in 2010 and is maintained by a small community of contributors, with Christine Ho noted as a co-maintainer; it is licensed under AGPL-3.0-or-later and hosted primarily on the movim.eu domain and GitHub. Architecturally, Movim is not itself an XMPP server; it is a responsive web client and application layer that connects to existing XMPP servers such as ejabberd or Prosody, meaning users need an XMPP/Jabber account (either self-hosted or from a public provider) to use it. Because it speaks the standard XMPP protocol, Movim interoperates with other XMPP clients such as Conversations, Pidgin, Xabber, and Gajim, and its official public instance runs at movim.eu alongside numerous independently operated public instances. Core features include one-to-one and group chat, video conferencing, OMEMO end-to-end encrypted messaging, a Markdown-based blogging and publication system for posting to a federated timeline, automatic link and image embedding, and topic-based Communities that function similarly to forums or subreddits but are federated across servers rather than centralized. There is no cloud SaaS product to subscribe to and no paid tier; the software is entirely free to self-host or to use via a public instance, funded through donations and volunteer development rather than commercial revenue. Movim's target audience is privacy-conscious users, decentralization advocates, and existing XMPP/Jabber communities who want a modern, social-network-style interface layered on top of federated messaging infrastructure, as an alternative to closed platforms like Facebook or Twitter/X. Its closest competitors and comparables are other federated/open social platforms such as Mastodon and Diaspora, and other XMPP web clients such as Converse.js and Snikket, though Movim differentiates itself by combining chat, blogging, and social networking in a single client built natively for the XMPP ecosystem rather than ActivityPub.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4bb6de5a-4c58-4a03-a3da-62dde82c521f';

