-- ── Mox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mox is a modern, all-in-one open-source mail server written in Go that bundles SMTP, IMAP4, webmail, and built-in spam and authentication protections into a single low-maintenance binary.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mox Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mox review 2026: see how this Go-based, all-in-one open-source mail server handles SMTP, IMAP, webmail, spam filtering, and self-hosted email setup.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mox is an open-source, all-in-one email server created by Dutch developer Mechiel Lukkien, with work on the project beginning around 2021. It is written in Go, a language chosen specifically to reduce memory-safety bugs common in older mail server codebases, and is released under the MIT license (incorporating some BSD-3-Clause code from the Go Authors and the Mozilla Public License-licensed Public Suffix List). Mox has received financial support from the NLnet Foundation and its NGI Zero programs (funded in part by the European Commission's Next Generation Internet initiative), including grants under NGI0 Entrust and NGI0 Core covering 2023 through early 2026, as well as support from the Netherlands Ministry of the Interior and Kingdom Relations, reflecting its status as a publicly-funded infrastructure project rather than a venture-backed company. Architecturally, Mox is unusual for combining functionality that is normally split across several separate daemons, an SMTP server for receiving, submitting, and delivering mail, a full IMAP4rev2 server for client access, and a built-in webmail interface, into one self-contained binary with no external dependencies beyond a database file it manages itself. It implements the modern authentication and delivery-security stack out of the box, including SPF, DKIM, and DMARC (with DMARC aggregate reporting), MTA-STS and DANE for encrypted delivery, TLS reporting (TLSRPT), and automatic TLS certificate provisioning via ACME/Let's Encrypt. For spam control, Mox uses per-account reputation tracking based on prior Junk/Non-Junk classification, Bayesian spam filtering that learns from user feedback, and connection throttling for first-time senders as an alternative to traditional greylisting. Administration is handled through a web-based admin interface for managing domains and accounts and reviewing DMARC/TLS reports, and Mox exposes a webhook and HTTP/JSON API for transactional email use cases, along with Prometheus metrics for monitoring. Setup is designed to be fast: an operator downloads the binary, runs a quickstart command, adds the DNS records it prints, and has a working mail server, positioning Mox against the traditional complexity of configuring Postfix, Dovecot, OpenDKIM, and SpamAssassin separately. Its target audience is technically capable individuals and small organizations who want to self-host email without maintaining a sprawling stack of interdependent daemons. Its closest competitors and comparison points are other self-hosted mail server projects such as Postfix plus Dovecot, Mailcow, Maddy, and Mail-in-a-Box, with Mox differentiating primarily through its single-binary Go implementation, security-by-default protocol support, and low ongoing maintenance burden.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba65b701-bea2-49e3-a8e6-c127d99725d5';

