-- ── mpd (Music Player Daemon) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Music Player Daemon (MPD) is a free, open-source background music server that plays audio files and manages playlists, controlled remotely by a wide variety of separate client applications.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MPD (Music Player Daemon) Review 2026: Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MPD review 2026: how the open-source Music Player Daemon works, its client/server architecture, supported formats, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Music Player Daemon, universally known as MPD, is a free and open-source, server-side music playback application originally developed by Max Kellermann and first released in 2003. Rather than being a conventional desktop music player with its own interface, MPD is a background daemon: it runs on a machine (commonly a home server, NAS, or single-board computer like a Raspberry Pi), maintains a database of a user's music library, manages playlists, and handles audio playback, while exposing a documented network protocol over TCP that separate client applications use to control it remotely. This client/server architecture is MPD's defining characteristic and the reason it has remained relevant for over two decades: because the playback engine is decoupled from the interface, a large and varied ecosystem of clients has grown around it, ranging from the official bundled command-line client mpc, to graphical desktop clients such as Cantata and Euphonica, to mobile apps and web-based interfaces, all of which can control the same running MPD instance simultaneously. MPD is written in C++ and licensed under the GNU General Public License version 2 (GPLv2), with active development continuing under the MusicPlayerDaemon organization on GitHub. Technically, MPD supports playback of common formats including FLAC, Ogg Vorbis, MP3, and HTTP audio streams, reads embedded metadata such as ID3 tags, Vorbis Comments, and MP4 metadata, and offers features like gapless playback, crossfading, seeking, and M3U playlist management. For audio output, it has native plugin support for ALSA, PulseAudio, OSS, JACK, and other backends, making it flexible across Linux-centric home audio setups. MPD does not sell anything and has no company behind it; it is maintained as a community open-source project with no venture funding, no headquarters, and no paid tiers. Its target audience is technically inclined home audio enthusiasts and self-hosters who want a lightweight, always-on music server they can control from any device on their network, often as the playback backend for whole-home audio setups. Notably, other self-hosted audio projects such as moOde Audio and various NAS-based music servers are built as front-ends or distributions layered on top of MPD rather than being competitors to it. Its closer comparables as standalone self-hosted music servers are projects like mStream, Navidrome, and Logitech Media Server (Squeezebox), though MPD differentiates through its minimalist, protocol-first design and its decades-long track record as foundational infrastructure for other music software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b68ce09a-b5d5-4d42-ab95-3e0f8ffbd563';

