-- ── mStream ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$mStream is a free, open-source, self-hosted music streaming server with its own web and mobile apps that lets you stream your personal music collection from anywhere.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$mStream Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$mStream review 2026: how this open-source, self-hosted music streaming server works, key features, setup, and how it compares to Navidrome and Plex.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$mStream is a free, open-source, self-hosted music streaming server that lets users access their personal music collection from any device through a built-in web player and dedicated mobile apps. The project, hosted primarily under the IrosTheBeggar GitHub account (associated with Iros Software) and at mstream.io, was created in 2015 and released under the GPL-3.0 license, with the GitHub repository having accumulated over 2,300 stars. Unlike commercial streaming services, mStream stores no music itself and pulls no catalog from a central company; it simply serves whatever audio files exist in folders on the machine it runs on, supporting formats including FLAC, MP3, WAV, OGG, Opus, AAC, M4A, and M4B. Architecturally, mStream is designed to be fast to deploy, its documentation advertises a roughly 30-second server setup, and it runs cross-platform on Windows, macOS, Linux, and FreeBSD, using the lightweight embedded database LokiJS rather than a heavier external database, plus libraries such as Symphonia and Lofty for audio metadata and processing. Its API is built to mirror the underlying folder structure directly, so users can browse and stream music even before a full library database has been built or scanned. Key features include gapless playback, a Milkdrop-based audio visualizer, playlist creation and sharing, drag-and-drop file uploading through the web interface, offline sync support for mobile apps, and built-in yt-dlp integration for pulling in audio. mStream also includes torrent client integration, supporting Transmission, Deluge, and qBittorrent, and a federation feature that lets independent mStream servers share specific directories with each other using invite tokens, an unusual capability that lets self-hosters loosely network their personal libraries. There are no paid tiers, subscriptions, or cloud-hosted version; the entire product is free software that users download and run on their own hardware, with official mobile apps available for iOS and Android alongside the browser-based player. mStream's target audience is technically comfortable music collectors and self-hosting enthusiasts who own large personal audio libraries (including lossless FLAC files) and want a private alternative to commercial streaming services like Spotify or Apple Music, with an emphasis on ownership, audio quality, and direct control of their files. Its closest competitors and comparables in the self-hosted space are Navidrome, Airsonic/Subsonic-compatible servers, and Music Player Daemon (MPD)-based setups, with mStream differentiating through its very fast setup process, built-in visualizer and torrent integration, and unique server-to-server federation feature.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6be73240-b846-4480-b296-99aefc7411ce';

