-- ── MTA:SA ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Multi Theft Auto: San Andreas (MTA:SA) is a free, open-source multiplayer mod that turns Grand Theft Auto: San Andreas into a networked, Lua-scriptable online game platform.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MTA:SA Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MTA:SA review 2026: how Multi Theft Auto: San Andreas turns GTA: San Andreas into free open-source multiplayer, its Lua scripting, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Multi Theft Auto: San Andreas, known as MTA:SA, is a free, open-source multiplayer modification for Rockstar's 2004 game Grand Theft Auto: San Andreas, developed by the volunteer MTA Team. The broader Multi Theft Auto project traces its roots back to 2003, when founder known as IJsVogel released an early two-player multiplayer prototype for the original Grand Theft Auto III under the name GTA3AM (GTA III Alternative Multiplayer); as interest grew, a wider group of volunteer programmers and webmasters joined the effort. The project moved through GTA III and GTA: Vice City multiplayer versions before its San Andreas iteration began taking shape, with early playable San Andreas content unveiled in January 2006 and the project eventually being revised and relaunched as fully open-source software licensed under GPLv3, with its source code hosted publicly on GitHub under the multitheftauto organization. MTA:SA functions as a game engine layered on top of the single-player game, injecting networked multiplayer functionality, custom game modes, and a sandbox environment that server owners can extend using the Lua scripting language. This scripting layer is central to MTA:SA's longevity: it allows individual servers to implement wildly different experiences, from realistic roleplay servers and racing modes to deathmatch and freeroam, all running on the same core engine, similar in spirit to how Garry's Mod or Counter-Strike server modding works. Because it is entirely free, non-commercial, and open source, MTA:SA has no company behind it, no headquarters, and no pricing tiers; the software and all official servers are maintained by the volunteer MTA Team and community contributors. Despite being built on a game originally released in 2004, MTA:SA has remained remarkably active into 2026, with community-reported daily concurrent player counts reportedly reaching into the tens of thousands, rivaling many modern commercially published multiplayer titles, largely due to its scripting flexibility and the strength of its roleplay and custom game-mode server communities. Its target audience is players and modders nostalgic for or newly discovering GTA: San Andreas, as well as scripters and server administrators who want to build custom multiplayer game modes on established game assets. Its closest comparables in the GTA modding space are SA-MP (San Andreas Multiplayer) and RAGE Multiplayer/FiveM (for later Grand Theft Auto titles), with MTA:SA differentiating through its fully open-source codebase, its long, continuous development history dating to the mid-2000s, and its mature Lua scripting ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cb496915-ab02-4433-8bfc-70ec1fc91a9c';

