-- ── multi-scrobbler ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$multi-scrobbler is an open-source, self-hosted tool that captures listening activity from multiple music sources like Spotify, Plex, and Jellyfin and scrobbles it to Last.fm, ListenBrainz, and Maloja.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$multi-scrobbler Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$multi-scrobbler review 2026: how this open-source, self-hosted scrobbling tool syncs listening history to Last.fm and ListenBrainz, plus setup and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$multi-scrobbler is a free, open-source, self-hosted application created and maintained by developer FoxxMD, distributed on GitHub under the MIT license with documentation hosted at foxxmd.github.io/multi-scrobbler. Its purpose is to solve music scrobble-tracking fragmentation: rather than needing a separate scrobbling app or browser extension for every platform someone listens to music on, multi-scrobbler runs as a single background service (most commonly deployed via Docker, though it can also run locally with Node.js) that connects directly to the APIs of multiple listening Sources and multiple scrobble Clients simultaneously. Supported Sources, the places music-listening activity is captured from, include services like Spotify, Plex, Jellyfin, Navidrome, YouTube Music, and existing Last.fm or ListenBrainz histories, among others; supported Clients, the destinations scrobbles are sent to, include Last.fm, ListenBrainz, and the self-hosted scrobble tracker Maloja. Because it talks to service APIs directly instead of relying on per-device or per-app plugins, multi-scrobbler captures listening activity regardless of which device or app was used to play the music, and its self-hosted, open-source nature means users retain full control and visibility over how their listening data is handled rather than trusting a third-party cloud service. The application includes a built-in web dashboard for viewing scrobble status, logs, and system health, and supports monitoring integrations including webhook notifications (Gotify, Ntfy, Apprise), healthcheck endpoints, and Prometheus metrics for users who want to track uptime in their own monitoring stack. It can also enhance or correct scrobble metadata using search-based pattern matching, built-in correction rules, or lookups against the MusicBrainz database, improving accuracy for cases like clean vs. explicit track titles or inconsistent artist naming. As with most projects in the self-hosted, single-maintainer open-source category, there is no company, headquarters, or funding round associated with multi-scrobbler; it is free to deploy and run indefinitely with no subscription or paid tier, and is commonly found within the broader self-hosted media stack alongside tools like Plex, Jellyfin, and Navidrome via platforms like Unraid and Docker Compose templates. Its target audience is music enthusiasts within the self-hosting and home media server community who want unified, accurate, and privately-controlled scrobbling across every app and device they use, especially those who run self-hosted music servers like Jellyfin or Navidrome that lack native Last.fm/ListenBrainz scrobbling of their own. Its closest comparables and competitors are native scrobbling plugins built into individual apps (such as a Jellyfin scrobbler plugin or a Plex Last.fm agent) and other cross-platform scrobbling tools, with multi-scrobbler differentiating by unifying many sources and destinations in one self-hosted service instead of requiring a separate integration per app.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c94279f7-118b-4aae-a54e-6cce37b4a7f3';

